// js/questions-y8.js — Year 8 NSW Science question bank (syllabus-aligned, regenerated)
window.QUESTION_BANK = window.QUESTION_BANK || {};
window.QUESTION_BANK[8] = {
  "living": [
    { q: "What is the correct order of biological organisation from simplest to most complex?", o: ["Cell, organ, tissue, organ system, organism", "Cell, tissue, organ, organ system, organism", "Tissue, cell, organ, organism, organ system", "Organ, cell, tissue, organ system, organism"], a: 1, exp: "Cells group into tissues, tissues combine to form organs, organs work together in organ systems, and all systems together make up an organism." },
    { q: "Which of the following best describes a tissue?", o: ["A single cell performing a specialised job", "A group of similar cells working together to carry out a shared function", "A collection of different organs with a common goal", "The smallest unit of life"], a: 1, exp: "A tissue is a group of similar cells that work together to perform a particular function, such as muscle tissue generating force." },
    { q: "What is the main role of the digestive system?", o: ["To transport oxygen to cells throughout the body", "To filter waste products from the blood", "To break down food into molecules small enough to be absorbed", "To exchange gases with the environment"], a: 2, exp: "The digestive system breaks food down into nutrients small enough to pass into the bloodstream and be used by cells." },
    { q: "Where does most chemical digestion and nutrient absorption occur in the human body?", o: ["Stomach", "Large intestine", "Oesophagus", "Small intestine"], a: 3, exp: "The small intestine is where most chemical digestion is completed and where nutrients are absorbed into the blood." },
    { q: "Which organ produces bile to help digest fats?", o: ["Pancreas", "Stomach", "Liver", "Kidney"], a: 2, exp: "The liver produces bile, which enters the small intestine to help break down fats." },
    { q: "What are the tiny air sacs in the lungs where gas exchange occurs called?", o: ["Bronchi", "Alveoli", "Bronchioles", "Capillaries"], a: 1, exp: "Alveoli are tiny air sacs with very thin walls and a rich blood supply, allowing oxygen and carbon dioxide to diffuse between air and blood." },
    { q: "Which muscle causes inhalation by contracting and flattening?", o: ["Intercostal muscle", "Diaphragm", "Abdominal muscle", "Heart muscle"], a: 1, exp: "The diaphragm flattens when it contracts, increasing the volume of the chest cavity and drawing air into the lungs." },
    { q: "What is the main waste product removed by the kidneys?", o: ["Carbon dioxide", "Bile", "Urea", "Glucose"], a: 2, exp: "The kidneys filter urea from the blood; urea is produced when proteins are broken down and is excreted in urine." },
    { q: "Which pathway does urine follow after leaving the kidney?", o: ["Kidney, urethra, bladder, ureter", "Kidney, ureter, bladder, urethra", "Kidney, bladder, ureter, urethra", "Kidney, ureter, urethra, bladder"], a: 1, exp: "Urine travels from each kidney down a ureter to the bladder, where it is stored, then exits through the urethra." },
    { q: "Which structural feature of red blood cells increases their surface area for absorbing oxygen?", o: ["They have a very large nucleus", "They are biconcave disc-shaped with no nucleus", "They have cilia on their surface", "They have thick rigid walls"], a: 1, exp: "Red blood cells are biconcave discs with no nucleus, giving them a large surface area relative to their volume for efficient oxygen absorption." },
    { q: "What do cilia do in the airways?", o: ["Absorb oxygen from the air", "Sweep mucus and debris upward away from the lungs", "Produce digestive enzymes", "Control the opening of stomata"], a: 1, exp: "Ciliated epithelial cells lining the airways beat their cilia to sweep mucus and trapped particles away from the lungs, preventing infection." },
    { q: "Why do the walls of alveoli need to be very thin?", o: ["To make the lungs lighter", "To allow the lungs to expand more", "To provide a short diffusion distance for gases", "To prevent air from leaking out"], a: 2, exp: "A thin wall means gases need to travel only a very short distance to diffuse between air in the alveolus and blood in surrounding capillaries." },
    { q: "What structural feature of the small intestine greatly increases its surface area for absorption?", o: ["A thick muscular wall", "Villi and microvilli on its inner surface", "A very large diameter", "A highly acidic environment"], a: 1, exp: "The small intestine is folded into villi and microvilli, creating a massive surface area of roughly 250 square metres for nutrient absorption." },
    { q: "Which organ system is responsible for transporting oxygen, nutrients, and waste products around the body?", o: ["Digestive system", "Excretory system", "Circulatory system", "Respiratory system"], a: 2, exp: "The circulatory system, comprising the heart, blood vessels, and blood, transports oxygen, nutrients, and waste throughout the body." },
    { q: "What is the difference between an artery and a vein?", o: ["Arteries carry blood to the lungs; veins carry blood to the body", "Arteries carry blood away from the heart; veins return blood to the heart", "Arteries carry deoxygenated blood; veins carry oxygenated blood", "Arteries are smaller than veins"], a: 1, exp: "Arteries carry blood away from the heart under high pressure, while veins return blood to the heart at lower pressure." },
    { q: "Which body system is primarily responsible for excreting carbon dioxide?", o: ["Digestive system", "Circulatory system", "The lungs as part of the excretory and respiratory systems", "Muscular system"], a: 2, exp: "The lungs excrete carbon dioxide with every exhalation; they are considered part of both the respiratory and excretory systems." },
    { q: "A person has one kidney removed. What is most likely to happen?", o: ["The remaining kidney enlarges and increases filtration to partially compensate", "The person immediately loses all kidney function", "The liver takes over all kidney functions", "The bladder grows larger to filter blood instead"], a: 0, exp: "After one kidney is removed, the remaining kidney can enlarge and increase its filtration rate to partially compensate for the reduced capacity." },
    { q: "Coeliac disease damages the villi of the small intestine. What is the main consequence?", o: ["The person cannot breathe properly", "The kidneys produce too much urine", "Nutrients cannot be properly absorbed, leading to malnutrition", "Blood cannot carry oxygen"], a: 2, exp: "Damage to intestinal villi reduces the absorptive surface area, causing malnutrition and fatigue even when the person eats enough food." },
    { q: "During vigorous exercise, what happens to blood flow in the digestive system?", o: ["It increases because the body needs more nutrients", "It decreases as blood is diverted to skeletal muscles", "It stays the same", "It stops completely"], a: 1, exp: "During exercise, blood is redirected away from the digestive system and toward the muscles, temporarily reducing digestive activity." },
    { q: "Which pair of body systems interact directly at the alveoli?", o: ["Digestive and circulatory", "Excretory and digestive", "Respiratory and circulatory", "Muscular and nervous"], a: 2, exp: "At the alveoli, oxygen moves from the lungs into the blood and carbon dioxide moves from blood into the lungs, linking the respiratory and circulatory systems." },
    { q: "What is the function of xylem in a plant?", o: ["To carry dissolved sugars from leaves to all plant parts", "To carry water and dissolved minerals from roots to leaves", "To produce food through photosynthesis", "To anchor the plant in the soil"], a: 1, exp: "Xylem vessels transport water and dissolved minerals upward from the roots to the leaves and other parts of the plant." },
    { q: "What is the function of phloem in a plant?", o: ["To carry water upward from roots to leaves", "To support the stem of the plant", "To carry dissolved sugars from leaves to all plant parts", "To absorb water from the soil"], a: 2, exp: "Phloem transports dissolved sugars produced during photosynthesis from the leaves to all other parts of the plant that need energy." },
    { q: "How does xylem tissue differ from phloem tissue in structure?", o: ["Xylem cells are living; phloem cells are dead", "Xylem cells are dead hollow tubes; phloem cells are living with sieve plates", "Xylem has sieve plates; phloem has lignified walls", "There is no structural difference"], a: 1, exp: "Xylem vessels are dead, hollow cells with lignified walls and no end walls, forming continuous tubes; phloem sieve-tube cells are living with perforated sieve plates." },
    { q: "Through which structures on a leaf surface does water vapour escape during transpiration?", o: ["Root hairs", "Chloroplasts", "Stomata", "Vascular bundles"], a: 2, exp: "Stomata are tiny pores on the leaf surface through which water vapour and gases pass in and out of the leaf." },
    { q: "What pulls water up through the xylem from roots to leaves?", o: ["The pumping action of root cells", "Transpiration pull as water evaporates from the leaves", "Gravity", "The expansion of xylem vessels"], a: 1, exp: "As water evaporates from the leaf surface through stomata, it creates a pulling force (transpiration pull) that draws water up the xylem from the roots." },
    { q: "What are the three main organs of a plant?", o: ["Leaves, flowers, and seeds", "Roots, stems, and leaves", "Roots, flowers, and fruits", "Bark, trunk, and leaves"], a: 1, exp: "The three main plant organs are roots (absorb water and anchor the plant), stems (support and transport), and leaves (site of photosynthesis)." },
    { q: "Which type of organism is a producer in an ecosystem?", o: ["An organism that eats only animals", "An organism that breaks down dead matter", "An organism that makes its own food using light energy", "An organism that eats both plants and animals"], a: 2, exp: "Producers (autotrophs) such as plants and algae make their own food through photosynthesis, forming the base of food chains." },
    { q: "What is the difference between a biotic and an abiotic factor in an ecosystem?", o: ["Biotic factors are non-living; abiotic factors are living", "Biotic factors are living organisms; abiotic factors are non-living physical components", "Biotic factors include temperature and water; abiotic factors include plants and animals", "There is no difference"], a: 1, exp: "Biotic factors are the living components of an ecosystem (plants, animals, fungi), while abiotic factors are the non-living physical components (temperature, water, sunlight, soil)." },
    { q: "What is the role of decomposers in an ecosystem?", o: ["They convert sunlight into chemical energy", "They hunt and eat other animals", "They break down dead organic material, releasing nutrients back into the environment", "They compete with plants for sunlight"], a: 2, exp: "Decomposers such as bacteria and fungi break down dead organisms and waste, releasing mineral nutrients back into the soil for plants to use." },
    { q: "What do the arrows in a food web represent?", o: ["Which organism is larger", "The direction of energy transfer from the organism being eaten to the one eating it", "The direction of matter flow from predator to prey", "The number of organisms at each level"], a: 1, exp: "Arrows in a food web point from the organism being eaten toward the organism eating it, showing the direction of energy transfer through the food web." },
    { q: "What is the 10 percent rule in ecology?", o: ["Only 10% of organisms survive in any ecosystem", "Approximately 10% of the energy at one trophic level is transferred to the next level", "Producers make up 10% of the total biomass", "Top predators get 10 times more energy than producers"], a: 1, exp: "On average only about 10% of the energy stored at one trophic level is passed on to the next; the remaining 90% is lost as heat, waste, and through respiration." },
    { q: "Why do food chains rarely have more than four or five links?", o: ["There are not enough species to fill more levels", "By the fourth or fifth level, there is too little energy left to support organisms", "Predators become too large to find food", "The top predators eat all organisms below them"], a: 1, exp: "Energy is lost at each trophic level, so by the fourth or fifth level so little energy remains that there is not enough to sustain another level of organisms." },
    { q: "What is the base of an ecological energy pyramid, and why?", o: ["Top predators, because they have the most energy", "Decomposers, because they recycle the most energy", "Producers, because they capture the most energy from sunlight", "Primary consumers, because there are the most of them"], a: 2, exp: "Producers form the widest base of an energy pyramid because they capture the most energy from sunlight; each level above is smaller due to energy loss." },
    { q: "What is an ecosystem?", o: ["Only the living organisms in a defined area", "Only the non-living physical environment of an area", "A community of living organisms interacting with each other and the non-living environment in a defined area", "A group of organisms of the same species living together"], a: 2, exp: "An ecosystem includes all the living organisms (biotic components) and the non-living physical environment (abiotic components) in a defined area, all interacting as a system." },
    { q: "Which of the following is an abiotic factor?", o: ["A eucalyptus tree", "A rabbit", "Bacteria in the soil", "The temperature of the air"], a: 3, exp: "Temperature is a non-living physical factor (abiotic), while trees, rabbits, and bacteria are living (biotic) components of an ecosystem." },
    { q: "What is a trophic level?", o: ["The total biomass of an ecosystem", "A feeding level in a food chain or food web", "The number of species in an ecosystem", "The depth of soil in an ecosystem"], a: 1, exp: "A trophic level is a feeding level in a food chain; producers are at level 1, primary consumers at level 2, secondary consumers at level 3, and so on." },
    { q: "Why must energy be continuously supplied to an ecosystem while matter does not need to be?", o: ["Matter is destroyed during reactions, so new matter must be added", "Energy flows through and is eventually lost as heat, while atoms are continuously recycled through decomposers", "Energy can be recycled but matter cannot", "Both energy and matter need to be continuously supplied"], a: 1, exp: "Energy enters as sunlight and is gradually lost as heat at each trophic level; matter (atoms) is continuously recycled through decomposers, so it does not need to be added." },
    { q: "What type of bacteria converts nitrogen gas from the atmosphere into a form plants can use?", o: ["Decomposing bacteria", "Nitrogen-fixing bacteria", "Denitrifying bacteria", "Pathogenic bacteria"], a: 1, exp: "Nitrogen-fixing bacteria, found in soil or in root nodules of legumes, convert atmospheric nitrogen gas into ammonia and nitrates that plants can absorb." },
    { q: "What is an introduced (invasive) species?", o: ["A species that has always lived in an area", "A species brought to an ecosystem where it did not previously exist", "A species that has become extinct", "A species that lives at the top of the food web"], a: 1, exp: "An introduced or invasive species is one that has been brought (intentionally or accidentally) to a new area where it did not previously live." },
    { q: "Why can an introduced species sometimes grow rapidly in a new environment?", o: ["It is always larger than native species", "It has no natural predators, competitors, or diseases in its new environment", "It is better adapted to photosynthesis", "It reproduces less than native species"], a: 1, exp: "Without natural predators, competitors, or diseases to limit its numbers, an introduced species can grow exponentially in its new environment." },
    { q: "Which introduced animal kills an estimated one to two billion native animals per year in Australia?", o: ["European rabbit", "Cane toad", "European red fox", "Feral cat"], a: 3, exp: "Feral cats are estimated to kill one to two billion native animals per year in Australia, making them one of the most devastating introduced predators." },
    { q: "What is the IUCN category for a species facing an extremely high risk of extinction in the wild?", o: ["Vulnerable", "Endangered", "Critically endangered", "Extinct in the wild"], a: 2, exp: "Critically endangered is the IUCN category for species facing an extremely high risk of extinction; it is one step below extinct in the wild." },
    { q: "What is meant by the carrying capacity of an environment?", o: ["The total number of species an ecosystem can support", "The maximum number of individuals of a population the environment can sustainably support given available resources", "The rate at which a population grows", "The minimum number of individuals needed for a species to survive"], a: 1, exp: "Carrying capacity is the maximum number of individuals of a species that an environment can sustainably support given its available food, water, space, and other resources." },
    { q: "Which of the following factors most directly caused the high extinction rate of Australian mammals since 1788?", o: ["Climate change reducing rainfall", "Introduction of predators such as cats and foxes, combined with habitat loss", "Hunting by Aboriginal peoples", "Disease brought by native insects"], a: 1, exp: "The introduction of cats, foxes, and rabbits by European settlers, combined with widespread land clearing, has caused Australia to have one of the world's worst mammal extinction records." },
    { q: "What is a predator-free sanctuary?", o: ["A nature reserve where no animals are allowed", "An area enclosed by fencing to exclude introduced predators, allowing native species to breed safely", "A national park where hunting is banned", "A zoo where endangered species are kept"], a: 1, exp: "A predator-free sanctuary is an area surrounded by predator-proof fencing where introduced animals such as foxes and cats are excluded, allowing native species to survive and breed safely." },
    { q: "What does the term extinct mean?", o: ["A species that is very rare and declining", "A species that no longer exists anywhere on Earth", "A species that only lives in captivity", "A species that has moved to a new habitat"], a: 1, exp: "A species is declared extinct when there is no reasonable doubt that its last living individual has died and it no longer exists anywhere on Earth." },
    { q: "What is biomass in ecology?", o: ["The total number of organisms in an ecosystem", "The total mass of living organic matter at a trophic level", "The speed at which energy moves through a food web", "The amount of sunlight reaching an ecosystem"], a: 1, exp: "Biomass is the total mass of living organic material at a trophic level; pyramids of biomass show that total mass generally decreases at each successive level." },
    { q: "Which biotic interaction benefits both species involved?", o: ["Predation", "Parasitism", "Competition", "Mutualism"], a: 3, exp: "Mutualism is a biotic interaction in which both species benefit; for example, a bee gains nectar from a flower and the flower is pollinated." },
    { q: "What is parasitism?", o: ["A relationship where both species benefit", "A relationship where one organism benefits at the expense of another without immediately killing it", "A relationship where both species compete for the same resource", "A relationship where one species eats another"], a: 1, exp: "In parasitism, the parasite benefits by obtaining nutrients from the host, while the host is harmed but usually not immediately killed." },
    { q: "What are guard cells and what do they do?", o: ["Cells that protect the plant from disease", "Kidney-shaped cells that control the opening and closing of stomata", "Cells in the root that absorb water", "Long hollow cells that transport water upward"], a: 1, exp: "Guard cells are kidney-shaped cells flanking each stoma; when they fill with water they bow apart opening the stoma, and when they lose water they close it." },
    { q: "Why do palisade mesophyll cells contain many chloroplasts?", o: ["To store water for the plant", "To support the leaf structure", "To maximise light absorption and photosynthesis", "To control gas exchange"], a: 2, exp: "Palisade mesophyll cells are packed with chloroplasts because they are the main site of photosynthesis, and more chloroplasts means more light can be absorbed." },
    { q: "How is a food web more realistic than a single food chain?", o: ["A food web only shows producers and top predators", "A food web shows many interconnected feeding relationships reflecting that most organisms eat more than one food source", "A food web shows energy being created at each level", "A food web only applies to aquatic ecosystems"], a: 1, exp: "A food web shows the many interconnected feeding relationships in an ecosystem, whereas a single food chain shows only one linear pathway and oversimplifies reality." },
    { q: "If all decomposers were suddenly removed from an ecosystem what would most likely happen?", o: ["Predator populations would immediately increase", "Dead organic material would accumulate and nutrients would not be returned to the soil, eventually harming producers", "The ecosystem would not be affected", "Herbivores would take over the role of decomposers"], a: 1, exp: "Without decomposers, dead matter would pile up, nutrients locked in organic material would not be recycled, and plant growth would eventually decline." },
    { q: "Which of the following correctly shows the flow of energy in a food chain?", o: ["Sun, consumer, producer, decomposer", "Sun, producer, primary consumer, secondary consumer", "Decomposer, producer, consumer, sun", "Producer, sun, consumer, decomposer"], a: 1, exp: "Energy flows from the Sun into producers through photosynthesis, then to primary consumers that eat producers, then to secondary consumers that eat primary consumers." },
    { q: "A species is described as vulnerable by the IUCN. What does this mean?", o: ["The species is already extinct", "The species faces an extremely high risk of extinction in the near future", "The species has a declining population and faces a high risk of extinction in the medium term", "The species is common and not at risk"], a: 2, exp: "Vulnerable means the species has a declining population and faces a high risk of extinction in the medium term if threatening processes continue." }
  ],
  "periodic": [
    { q: "What is an element?", o: ["A pure substance made of two or more types of atom joined together", "A pure substance made from only one type of atom", "A mixture of different substances", "A substance that cannot be seen"], a: 1, exp: "An element is a pure substance made entirely from one type of atom; all atoms of the same element are identical to each other." },
    { q: "What is an atom?", o: ["The smallest particle of a compound", "The smallest unit of an element that still has the properties of that element", "A group of molecules joined together", "A type of chemical formula"], a: 1, exp: "An atom is the smallest particle of an element that still retains the properties of that element; dividing it further gives only sub-atomic particles." },
    { q: "Approximately how many naturally occurring elements exist on Earth?", o: ["About 50", "About 94", "About 118", "About 200"], a: 1, exp: "There are about 94 naturally occurring elements on Earth, though scientists have created additional elements in laboratories, bringing the total to 118." },
    { q: "What is the chemical symbol for iron?", o: ["Ir", "Fe", "In", "Io"], a: 1, exp: "The symbol for iron is Fe, from its Latin name Ferrum." },
    { q: "What is the chemical symbol for sodium?", o: ["So", "S", "Na", "Sd"], a: 2, exp: "The symbol for sodium is Na, from its Latin name Natrium." },
    { q: "What is the chemical symbol for gold?", o: ["Gd", "Go", "Gl", "Au"], a: 3, exp: "The symbol for gold is Au, from its Latin name Aurum." },
    { q: "What is the chemical symbol for potassium?", o: ["P", "Po", "K", "Pt"], a: 2, exp: "The symbol for potassium is K, from its Latin name Kalium." },
    { q: "What is the chemical symbol for copper?", o: ["Co", "Cp", "Ca", "Cu"], a: 3, exp: "The symbol for copper is Cu, from its Latin name Cuprum." },
    { q: "What is the correct symbol for the element chlorine?", o: ["CL", "cl", "Cl", "CH"], a: 2, exp: "Element symbols always have the first letter capitalised and the second letter (if any) in lower case, so chlorine is Cl." },
    { q: "Which of the following is a property of metals?", o: ["Brittle and dull", "Good conductors of heat and electricity, and malleable", "Usually gases at room temperature", "Poor conductors of electricity"], a: 1, exp: "Metals are typically shiny, good conductors of heat and electricity, malleable (can be hammered into sheets), and ductile (can be drawn into wires)." },
    { q: "Which of the following is a property of non-metals?", o: ["Ductile and shiny", "Good conductors of electricity", "Usually brittle as solids and poor conductors of electricity", "High density"], a: 2, exp: "Non-metals are typically dull, brittle when solid, poor conductors of heat and electricity, and often gases at room temperature." },
    { q: "What is a metalloid?", o: ["A type of metal that is very soft", "An element with properties intermediate between metals and non-metals", "A mixture of two metals", "A non-metallic element that conducts electricity"], a: 1, exp: "Metalloids such as silicon and germanium have properties that are a mix of metals and non-metals; they are often semiconductors." },
    { q: "Which element is described as a semiconductor and is used in computer chips?", o: ["Copper", "Carbon", "Silicon", "Aluminium"], a: 2, exp: "Silicon is a metalloid and semiconductor; it can conduct electricity under some conditions but not others, making it essential for computer chips." },
    { q: "Which is the only metal that is liquid at room temperature?", o: ["Gallium", "Mercury", "Lead", "Tin"], a: 1, exp: "Mercury is the only metal that is liquid at room temperature; all other metals are solid under normal conditions." },
    { q: "What does malleable mean?", o: ["Can be drawn into thin wires without breaking", "Can be hammered into sheets without shattering", "Shiny and reflective", "Resistant to corrosion"], a: 1, exp: "Malleable means a material can be hammered or pressed into different shapes without breaking; this is a key property of most metals." },
    { q: "What does ductile mean?", o: ["Can be hammered into sheets", "Can be stretched into wires without breaking", "Has a high melting point", "Reacts vigorously with water"], a: 1, exp: "Ductile means a material can be stretched or drawn out into thin wires without breaking; copper and aluminium are highly ductile metals." },
    { q: "What subatomic particles are found in the nucleus of an atom?", o: ["Electrons and protons", "Protons and neutrons", "Electrons and neutrons", "Protons only"], a: 1, exp: "The nucleus of an atom contains protons (positively charged) and neutrons (no charge); electrons orbit the nucleus in shells." },
    { q: "What is the charge of a proton?", o: ["Zero", "Negative", "Positive", "Double positive"], a: 2, exp: "Protons carry a relative charge of +1; they are found in the nucleus of the atom." },
    { q: "What is the charge of an electron?", o: ["Zero", "Negative", "Positive", "Double negative"], a: 1, exp: "Electrons carry a relative charge of -1; they orbit the nucleus in shells (energy levels)." },
    { q: "Which subatomic particle has almost no mass?", o: ["Proton", "Neutron", "Electron", "Nucleus"], a: 2, exp: "Electrons have a negligible mass compared to protons and neutrons; an electron is about 1836 times lighter than a proton." },
    { q: "Why is an atom electrically neutral?", o: ["Because it has no charged particles inside it", "Because the number of protons equals the number of electrons so positive and negative charges cancel", "Because neutrons cancel the charge of protons", "Because electrons do not have a charge"], a: 1, exp: "An atom has equal numbers of protons (+1 each) and electrons (-1 each), so the charges cancel out and the atom has no overall charge." },
    { q: "In the planetary model of the atom where are the electrons located?", o: ["In the nucleus alongside protons", "In fixed shells orbiting the nucleus", "Randomly scattered throughout the atom", "Between the protons and neutrons"], a: 1, exp: "In the Bohr planetary model, electrons orbit the nucleus in fixed shells or energy levels, similar to how planets orbit the Sun." },
    { q: "How many electrons can the first electron shell hold?", o: ["1", "2", "8", "18"], a: 1, exp: "The first electron shell (closest to the nucleus) can hold a maximum of 2 electrons before electrons begin filling the second shell." },
    { q: "How many electrons can the second electron shell hold?", o: ["2", "4", "8", "18"], a: 2, exp: "The second electron shell can hold a maximum of 8 electrons; once it is full, electrons start filling the third shell." },
    { q: "What is the electron arrangement of sodium which has atomic number 11?", o: ["2, 9", "3, 8", "2, 8, 1", "2, 8, 3"], a: 2, exp: "Sodium has 11 electrons arranged as 2 in the first shell, 8 in the second shell, and 1 in the third shell." },
    { q: "What is the electron arrangement of oxygen which has atomic number 8?", o: ["2, 6", "1, 7", "2, 4, 2", "4, 4"], a: 0, exp: "Oxygen has 8 electrons arranged as 2 in the first shell and 6 in the second shell." },
    { q: "What is the atomic number of an element?", o: ["The number of neutrons in the nucleus", "The number of protons in the nucleus of the atom", "The total mass of the atom", "The number of electrons in the outermost shell"], a: 1, exp: "The atomic number is the number of protons in the nucleus; it uniquely identifies each element and determines its position in the periodic table." },
    { q: "How are elements ordered in the modern periodic table?", o: ["By alphabetical order of their names", "By increasing atomic mass", "By increasing atomic number", "By their state at room temperature"], a: 2, exp: "The modern periodic table arranges elements in order of increasing atomic number (number of protons), which was established by Henry Moseley in 1913." },
    { q: "What are the vertical columns of the periodic table called?", o: ["Periods", "Rows", "Groups", "Shells"], a: 2, exp: "The vertical columns of the periodic table are called groups; elements in the same group have similar chemical properties because they have the same number of outer electrons." },
    { q: "What are the horizontal rows of the periodic table called?", o: ["Groups", "Periods", "Shells", "Series"], a: 1, exp: "The horizontal rows of the periodic table are called periods; the period number tells you how many electron shells an atom of that element has." },
    { q: "Why do elements in the same group of the periodic table behave similarly?", o: ["They have the same atomic mass", "They have the same number of electrons in their outermost shell", "They are all the same size", "They were all discovered at the same time"], a: 1, exp: "Elements in the same group have the same number of electrons in their outer shell; the outer electron arrangement determines chemical behaviour." },
    { q: "Which group contains the noble gases?", o: ["Group 1", "Group 2", "Group 17", "Group 18"], a: 3, exp: "Group 18 contains the noble gases (helium, neon, argon, etc.); they have full outer electron shells and are almost completely unreactive." },
    { q: "Which group is the alkali metals and how does reactivity change going down the group?", o: ["Group 2; reactivity decreases going down", "Group 1; reactivity increases going down", "Group 17; reactivity increases going down", "Group 1; reactivity decreases going down"], a: 1, exp: "Group 1 elements are the alkali metals; their reactivity increases going down the group so caesium is more reactive than lithium." },
    { q: "Which group is known as the halogens?", o: ["Group 1", "Group 2", "Group 17", "Group 18"], a: 2, exp: "Group 17 elements are the halogens (fluorine, chlorine, bromine, iodine); they are very reactive non-metals with 7 outer electrons." },
    { q: "How does the reactivity of halogens change going down Group 17?", o: ["Reactivity increases going down", "Reactivity decreases going down", "Reactivity stays the same", "Reactivity first increases then decreases"], a: 1, exp: "Halogen reactivity decreases going down Group 17; fluorine is the most reactive halogen and iodine is the least reactive of the common halogens." },
    { q: "What does an element's period number tell you?", o: ["How reactive it is", "How many protons it has", "How many electron shells its atoms have", "How many neutrons are in its nucleus"], a: 2, exp: "The period number tells you the number of electron shells in an atom of that element; period 3 elements such as sodium have 3 electron shells." },
    { q: "Who is most credited with creating the first widely accepted periodic table?", o: ["John Dalton", "Henry Moseley", "Dmitri Mendeleev", "Ernest Rutherford"], a: 2, exp: "Dmitri Mendeleev arranged the 63 known elements by atomic mass and chemical properties in 1869 and is regarded as the father of the periodic table." },
    { q: "What significant thing did Mendeleev do when he could not find an element to fit a particular position?", o: ["He removed that row from the table", "He left a gap and predicted that an element would eventually be found to fill it", "He put two elements in the same position", "He reordered the elements by size"], a: 1, exp: "Mendeleev left gaps in his table and predicted the properties of missing elements; when those elements such as gallium and germanium were later discovered, they matched his predictions closely." },
    { q: "What did Thomson's plum pudding model of the atom propose?", o: ["The atom was a solid unbreakable sphere", "Electrons were embedded in a ball of positive charge", "Electrons orbited the nucleus in fixed shells", "The atom was mostly empty space with a tiny dense nucleus"], a: 1, exp: "Thomson's plum pudding model proposed that atoms were balls of positive charge with negatively charged electrons scattered through them like plums in a pudding." },
    { q: "What did Rutherford's gold foil experiment reveal about the atom?", o: ["That atoms are solid spheres with no internal structure", "That atoms are mostly empty space with a tiny dense positively charged nucleus at the centre", "That electrons travel in fixed orbits around the nucleus", "That protons and neutrons have equal charge"], a: 1, exp: "Rutherford found that most alpha particles passed straight through gold foil but a few bounced back, showing atoms are mostly empty space with a tiny dense positive nucleus." },
    { q: "What did Bohr add to Rutherford's nuclear model of the atom?", o: ["The discovery of the neutron", "The idea that the nucleus contains protons", "The idea that electrons orbit the nucleus in specific fixed shells", "The idea that atoms are mostly empty space"], a: 2, exp: "Bohr improved Rutherford's model by proposing that electrons orbit the nucleus in specific fixed energy levels (shells), similar to planets around the Sun." },
    { q: "What elements are found in water H2O?", o: ["Hydrogen and nitrogen", "Helium and oxygen", "Hydrogen and oxygen", "Hydrogen and carbon"], a: 2, exp: "Water (H2O) contains hydrogen (H) and oxygen (O); the formula shows 2 hydrogen atoms and 1 oxygen atom in each molecule." },
    { q: "What elements are found in carbon dioxide CO2?", o: ["Calcium and oxygen", "Carbon and oxygen", "Carbon and hydrogen", "Calcium and hydrogen"], a: 1, exp: "Carbon dioxide (CO2) contains carbon (C) and oxygen (O); the subscript 2 shows there are 2 oxygen atoms for every 1 carbon atom." },
    { q: "What elements are found in table salt NaCl?", o: ["Nitrogen and chlorine", "Sodium and calcium", "Nitrogen and calcium", "Sodium and chlorine"], a: 3, exp: "Table salt is sodium chloride (NaCl), containing sodium (Na) and chlorine (Cl) in a 1:1 ratio." },
    { q: "What is an alloy?", o: ["A pure element with special properties", "A compound formed when two non-metals react", "A mixture of a metal with one or more other elements", "A type of metalloid"], a: 2, exp: "An alloy is a mixture of a metal with one or more other elements (usually other metals or carbon) designed to improve properties such as strength or corrosion resistance." },
    { q: "What is steel and what makes it useful for buildings and vehicles?", o: ["A pure iron element; it is very light", "An alloy of iron and carbon; it is much stronger than pure iron", "A compound of iron and oxygen; it does not rust", "A mixture of copper and zinc; it is attractive and hard"], a: 1, exp: "Steel is an alloy of iron and carbon; the addition of carbon makes it much stronger than pure iron, making it ideal for buildings, cars, and tools." },
    { q: "Why is copper used for electrical wiring?", o: ["Because it is the cheapest metal", "Because it is an excellent conductor of electricity and is ductile", "Because it is the lightest metal", "Because it does not conduct electricity and acts as insulation"], a: 1, exp: "Copper is used for electrical wiring because it is an excellent conductor of electricity, can be drawn into long thin wires (ductile), and is affordable." },
    { q: "How many electron shells does an atom of chlorine with atomic number 17 have?", o: ["1", "2", "3", "4"], a: 2, exp: "Chlorine is in Period 3 of the periodic table, so its atoms have 3 electron shells with the arrangement 2, 8, 7." },
    { q: "Helium and neon are both in Group 18. What do they have in common regarding their electron arrangement?", o: ["Both have 2 electrons in their outer shell", "Both have completely full outer electron shells", "Both have the same number of protons", "Both have empty outer shells"], a: 1, exp: "Group 18 noble gases all have completely full outer electron shells (helium has 2 in its single shell; neon has 8 in its outer second shell), making them unreactive." },
    { q: "An element is in Group 1 and Period 2. How many outer electrons does it have and how many shells?", o: ["2 outer electrons and 1 shell", "1 outer electron and 2 shells", "7 outer electrons and 2 shells", "2 outer electrons and 2 shells"], a: 1, exp: "Group 1 means 1 outer electron; Period 2 means 2 electron shells. This describes lithium (Li) with the electron arrangement 2, 1." },
    { q: "Why is aluminium used in aircraft bodies rather than iron?", o: ["Aluminium is a better conductor of electricity", "Aluminium has a much lower density than iron making aircraft lighter and more fuel-efficient", "Aluminium is stronger than iron", "Aluminium is more common than iron"], a: 1, exp: "Aluminium has a much lower density than iron, so aircraft made of aluminium alloys are lighter, use less fuel, and can carry greater payloads." },
    { q: "What gas makes up approximately 78% of the air we breathe?", o: ["Oxygen", "Carbon dioxide", "Nitrogen", "Argon"], a: 2, exp: "Nitrogen (N) makes up about 78% of the atmosphere; oxygen makes up about 21%, with other gases making up the remainder." },
    { q: "Which of the following correctly states the rule for writing element symbols?", o: ["All letters are lowercase", "All letters are uppercase", "The first letter is uppercase and the second letter if any is lowercase", "The first letter is lowercase and the second is uppercase"], a: 2, exp: "Element symbols always begin with a capital letter; if there is a second letter it must be lowercase (e.g. Ca for calcium, not CA or ca)." },
    { q: "What technology led to the discovery of the electron which changed the atomic model?", o: ["Particle accelerator", "Cathode ray tube", "Spectroscope", "Scanning tunnelling microscope"], a: 1, exp: "J.J. Thomson used cathode ray tubes in the late 1800s to discover the electron, showing for the first time that atoms are made of smaller particles." },
    { q: "Elements in Period 3 of the periodic table all have how many electron shells?", o: ["1", "2", "3", "4"], a: 2, exp: "The period number equals the number of electron shells; all Period 3 elements from sodium to argon have 3 electron shells." },
    { q: "If an element has 15 electrons what is its electron arrangement?", o: ["2, 13", "2, 8, 5", "2, 7, 6", "5, 5, 5"], a: 1, exp: "With 15 electrons: 2 fill the first shell, 8 fill the second, and the remaining 5 go into the third shell, giving the arrangement 2, 8, 5 (this is phosphorus)." },
    { q: "What is the chemical symbol for silver?", o: ["Si", "Sv", "Ag", "Sr"], a: 2, exp: "The symbol for silver is Ag, from its Latin name Argentum." },
    { q: "What is the chemical symbol for lead?", o: ["Le", "Ld", "Pb", "Pd"], a: 2, exp: "The symbol for lead is Pb, from its Latin name Plumbum." },
    { q: "What is stainless steel and why is it used for surgical instruments?", o: ["Pure iron that has been polished; it looks clean", "An alloy of iron, chromium, and nickel that does not rust", "A compound of iron and oxygen that is very hard", "A mixture of iron and carbon that is very strong"], a: 1, exp: "Stainless steel is an alloy of iron, chromium, and nickel; the chromium prevents rusting, making it hygienic and durable for surgical instruments and kitchen equipment." },
    { q: "Which group in the periodic table contains elements that are very reactive with water and are soft metals?", o: ["Group 18 noble gases", "Group 17 halogens", "Group 1 alkali metals", "Group 2 alkaline earth metals"], a: 2, exp: "Group 1 alkali metals (lithium, sodium, potassium) are soft, shiny metals that react vigorously with water; their reactivity increases going down the group." }
  ],
  "change": [
    { q: "What are the three ways in which thermal energy can be transferred?", o: ["Evaporation, condensation, and radiation", "Conduction, convection, and radiation", "Conduction, evaporation, and reflection", "Radiation, diffusion, and convection"], a: 1, exp: "Thermal energy is transferred by conduction (through solids via vibrating particles), convection (in fluids via bulk flow), and radiation (as electromagnetic waves needing no medium)." },
    { q: "Which mode of heat transfer occurs when vibrating particles in a solid pass energy to neighbouring particles?", o: ["Convection", "Radiation", "Conduction", "Evaporation"], a: 2, exp: "Conduction occurs when particles in direct contact transfer energy by vibrating and colliding with neighbouring particles; no material moves from place to place." },
    { q: "Which mode of heat transfer requires no medium and can travel through a vacuum?", o: ["Conduction", "Convection", "Radiation", "Diffusion"], a: 2, exp: "Radiation is the transfer of energy as electromagnetic waves (infrared); it does not need any medium and is how the Sun's energy reaches Earth through the vacuum of space." },
    { q: "Which mode of heat transfer occurs in fluids when warmer less-dense fluid rises and cooler denser fluid sinks?", o: ["Conduction", "Convection", "Radiation", "Condensation"], a: 1, exp: "Convection occurs in fluids when warmer less-dense regions rise and cooler denser regions sink, creating circulating currents that carry thermal energy." },
    { q: "Why do metals feel cold to touch even at room temperature?", o: ["Metals are always cooler than room temperature", "Metals are good conductors of heat and rapidly conduct heat away from your skin", "Metals reflect heat away from your hand", "Metals produce a cooling chemical reaction when touched"], a: 1, exp: "Metals are good thermal conductors; they rapidly conduct heat away from the warm skin, creating the sensation of cold even when the metal is at the same temperature as the room." },
    { q: "What is kinetic energy?", o: ["Energy stored in the chemical bonds of a substance", "Energy an object has because it is moving", "Energy stored due to an object's position or height", "Energy transferred by electromagnetic waves"], a: 1, exp: "Kinetic energy is the energy an object possesses because it is moving; the faster it moves and the greater its mass, the more kinetic energy it has." },
    { q: "What is gravitational potential energy?", o: ["Energy stored in stretched or compressed materials", "Energy stored in chemical bonds", "Energy stored due to an object's height above a reference point", "Energy carried by moving particles"], a: 2, exp: "Gravitational potential energy is stored energy that depends on an object's height; the higher an object is above a reference level, the more gravitational PE it stores." },
    { q: "Where is chemical potential energy stored?", o: ["In the motion of particles", "In the height of an object above the ground", "In chemical bonds between atoms such as in food and fuels", "In the temperature of a substance"], a: 2, exp: "Chemical potential energy is stored in the chemical bonds between atoms; food, fuels, and batteries all store chemical PE that is released during chemical reactions." },
    { q: "A compressed spring stores which type of energy?", o: ["Gravitational potential energy", "Kinetic energy", "Elastic potential energy", "Chemical potential energy"], a: 2, exp: "A compressed or stretched spring stores elastic potential energy; this energy is released as kinetic energy when the spring returns to its natural shape." },
    { q: "What energy transformation occurs in a solar panel?", o: ["Chemical energy to electrical energy", "Kinetic energy to electrical energy", "Radiant light energy to electrical energy", "Thermal energy to chemical energy"], a: 2, exp: "A photovoltaic solar panel converts radiant energy from sunlight directly into electrical energy using semiconductor materials." },
    { q: "What is the law of conservation of energy?", o: ["Energy can be created from nothing when needed", "Energy can only be destroyed by chemical reactions", "Energy cannot be created or destroyed; it can only be transformed or transferred", "Energy is always lost as heat in every process"], a: 2, exp: "The law of conservation of energy states that energy cannot be created or destroyed; it can only be transformed from one form to another or transferred from one object to another." },
    { q: "A ball is held above the ground. As it falls what energy transformation occurs?", o: ["Kinetic energy to gravitational potential energy", "Gravitational potential energy to kinetic energy", "Chemical energy to kinetic energy", "Thermal energy to kinetic energy"], a: 1, exp: "As the ball falls, its gravitational potential energy is converted into kinetic energy as it accelerates toward the ground." },
    { q: "What form does wasted energy most commonly take?", o: ["Kinetic energy", "Chemical energy", "Thermal energy that spreads into the surroundings", "Light energy"], a: 2, exp: "In most energy transformations, some energy is converted into thermal energy that disperses into the surroundings and cannot be easily recovered for useful work." },
    { q: "What is the difference between a physical change and a chemical change?", o: ["A physical change produces a new substance; a chemical change does not", "A physical change alters form without producing new substances; a chemical change produces new substances with different properties", "Physical changes are always reversible; chemical changes are always irreversible", "There is no difference between physical and chemical changes"], a: 1, exp: "A physical change alters the form or appearance of a substance without creating new substances; a chemical change produces new substances with different properties from the originals." },
    { q: "Which of the following is an example of a chemical change?", o: ["Melting ice into water", "Dissolving sugar in water", "Cutting a piece of paper in half", "Burning wood to produce ash and smoke"], a: 3, exp: "Burning wood is a chemical change because new substances (ash, carbon dioxide, water vapour) are produced that have different properties from the original wood." },
    { q: "Which of the following is an example of a physical change?", o: ["Rusting iron", "Baking a cake", "Dissolving sugar in water", "Burning a candle"], a: 2, exp: "Dissolving sugar in water is a physical change; no new substance is formed and the sugar can be recovered by evaporating the water." },
    { q: "What are the five indicators of a chemical change?", o: ["Melting, dissolving, freezing, cutting, mixing", "Colour change, gas production, precipitate formation, temperature change, and difficulty reversing the change", "Bubbles, smell, light, sound, and movement", "Change in mass, volume, shape, colour, and density"], a: 1, exp: "The five key indicators of a chemical change are: colour change, gas production (bubbles or odour), precipitate formation, temperature change, and the change being difficult to reverse." },
    { q: "What is a precipitate?", o: ["A gas produced during a chemical reaction", "A solid that forms in a liquid during a chemical reaction", "A liquid that turns into a gas when heated", "A type of catalyst that speeds up reactions"], a: 1, exp: "A precipitate is a solid that suddenly appears in a liquid when two solutions are mixed, indicating that a chemical reaction has taken place." },
    { q: "What is the difference between an exothermic and an endothermic reaction?", o: ["Exothermic reactions need heat to start; endothermic reactions produce heat", "Exothermic reactions release heat to the surroundings; endothermic reactions absorb heat from the surroundings", "Exothermic reactions are physical changes; endothermic reactions are chemical changes", "Both types produce heat but at different rates"], a: 1, exp: "Exothermic reactions release energy to the surroundings causing the temperature to rise; endothermic reactions absorb energy from the surroundings causing the temperature to fall." },
    { q: "Which of the following is an exothermic reaction?", o: ["Dissolving ammonium nitrate in water", "Photosynthesis", "An instant cold pack being activated", "Burning natural gas"], a: 3, exp: "Burning natural gas is exothermic; it releases heat and light energy to the surroundings, causing the temperature to rise." },
    { q: "Which of the following is an endothermic reaction?", o: ["Combustion of wood", "Neutralisation of an acid and base", "Dissolving ammonium nitrate in water used in instant cold packs", "Rusting of iron"], a: 2, exp: "Dissolving ammonium nitrate in water is endothermic; it absorbs heat from the surroundings, causing the temperature to drop, which is why it is used in instant cold packs." },
    { q: "What is a word equation in chemistry?", o: ["A description of a scientist's feelings about a reaction", "A representation showing reactants on the left and products on the right separated by an arrow", "A mathematical formula for calculating energy", "A list of equipment needed for an experiment"], a: 1, exp: "A word equation shows the names of the reactants (starting substances) on the left of an arrow and the products (new substances formed) on the right." },
    { q: "In a word equation what are the substances written on the left-hand side of the arrow called?", o: ["Products", "Catalysts", "Reactants", "Indicators"], a: 2, exp: "The substances that react at the start are called reactants; they are written on the left-hand side of the arrow in a word equation." },
    { q: "What is the word equation for aerobic respiration?", o: ["Carbon dioxide + water to give glucose + oxygen", "Glucose + oxygen to give carbon dioxide + water", "Glucose + carbon dioxide to give water + oxygen", "Oxygen + water to give glucose + carbon dioxide"], a: 1, exp: "Aerobic respiration breaks down glucose using oxygen, releasing energy and producing carbon dioxide and water as waste products." },
    { q: "What is the word equation for photosynthesis?", o: ["Glucose + oxygen to give carbon dioxide + water", "Carbon dioxide + water to give glucose + oxygen", "Oxygen + glucose to give water + carbon dioxide", "Water + glucose to give carbon dioxide + oxygen"], a: 1, exp: "Photosynthesis uses light energy to convert carbon dioxide and water into glucose (chemical energy) and oxygen." },
    { q: "Where in the plant cell does photosynthesis take place?", o: ["Mitochondria", "Nucleus", "Chloroplasts", "Cell membrane"], a: 2, exp: "Photosynthesis takes place in the chloroplasts, which contain chlorophyll, the green pigment that absorbs light energy." },
    { q: "Where in the cell does aerobic respiration mainly take place?", o: ["Chloroplasts", "Nucleus", "Cell wall", "Mitochondria"], a: 3, exp: "Aerobic respiration occurs mainly in the mitochondria, where glucose and oxygen are used to release energy for the cell." },
    { q: "What are tectonic plates?", o: ["Large rigid slabs that make up Earth's outer shell and move slowly", "The layers of rock deep inside Earth's mantle", "Only the oceanic crust not continental crust", "Sections of Earth's core"], a: 0, exp: "Tectonic plates are large rigid slabs that make up Earth's outer shell (lithosphere); they move slowly over the underlying mantle, driven by convection currents." },
    { q: "What drives the movement of tectonic plates?", o: ["The gravitational pull of the Moon", "Convection currents in the mantle", "Volcanic eruptions pushing plates apart", "The rotation of Earth"], a: 1, exp: "Convection currents in the hot mantle drag the overlying tectonic plates; hot rock rises, spreads, cools, and sinks, carrying plates with it." },
    { q: "What happens at a divergent plate boundary?", o: ["Two plates collide and one is pushed under the other", "Two plates slide past each other horizontally", "Two plates move apart and new crust forms to fill the gap", "One plate is entirely destroyed"], a: 2, exp: "At a divergent boundary, plates move apart; magma rises to fill the gap and solidifies, forming new oceanic crust such as at mid-ocean ridges." },
    { q: "What is the name of the ancient supercontinent that Alfred Wegener proposed had once existed?", o: ["Laurasia", "Gondwana", "Pangaea", "Panthalassa"], a: 2, exp: "Wegener proposed in 1912 that the continents had once been joined in a single supercontinent he called Pangaea, which later broke apart and drifted to form today's continents." },
    { q: "What type of fossil evidence supports the theory of plate tectonics?", o: ["Finding different fossils on opposite sides of the same continent", "Finding identical fossils of the same species on continents now separated by thousands of kilometres of ocean", "Finding no fossils in ocean sediment", "Finding fossils only in tropical regions"], a: 1, exp: "Identical fossils of species such as Glossopteris (a plant) and Mesosaurus (a reptile) found on continents now separated by oceans suggest those landmasses were once joined." },
    { q: "What are the three types of rock?", o: ["Hard, soft, and medium", "Igneous, sedimentary, and metamorphic", "Volcanic, oceanic, and continental", "Crystal, layered, and foliated"], a: 1, exp: "Rocks are classified into three main types: igneous (formed from cooling magma or lava), sedimentary (formed from compacted sediment), and metamorphic (formed by heat and pressure)." },
    { q: "Which type of rock most commonly contains fossils and why?", o: ["Igneous, because lava traps organisms", "Metamorphic, because heat and pressure preserve organisms", "Sedimentary, because organisms are buried in layers of sediment before they decompose", "All three types contain fossils equally"], a: 2, exp: "Fossils are most common in sedimentary rock because organisms can be buried in accumulating layers of sediment before they decompose; the sediment later compacts into rock around the remains." },
    { q: "What is the law of superposition?", o: ["Heavier rocks always sink to the bottom of a river", "In an undisturbed sequence of sedimentary rock layers the oldest layers are at the bottom and the youngest are at the top", "Metamorphic rocks are always found below igneous rocks", "All rock types form at the same rate"], a: 1, exp: "The law of superposition states that in undisturbed rock strata, each layer was deposited on top of the previous one, so lower layers are older and upper layers are younger." },
    { q: "How do igneous rocks with large crystals like granite differ from those with small crystals like basalt?", o: ["Granite forms from lava; basalt forms from magma", "Granite cools slowly underground allowing large crystals to form; basalt cools rapidly at the surface forming small crystals", "Granite and basalt are the same rock", "Granite forms in water; basalt forms in air"], a: 1, exp: "Granite cools slowly deep underground, giving crystals time to grow large; basalt cools rapidly when lava reaches the surface, producing small fine-grained crystals." },
    { q: "What is a fossil?", o: ["Any rock that is very old", "The preserved remains or trace of an organism that lived in the past", "A mineral with a crystalline structure", "An igneous rock formed from volcanic lava"], a: 1, exp: "A fossil is the preserved remains, impression, or trace of an organism that lived in the past, most commonly found in sedimentary rock." },
    { q: "What two main conditions are needed to form metamorphic rock?", o: ["Water and wind", "Heat and pressure", "Cooling and solidification", "Compaction and cementation"], a: 1, exp: "Metamorphic rocks form when existing rocks are subjected to intense heat and pressure deep within the Earth's crust, causing mineral recrystallisation without melting." },
    { q: "What is the rock cycle?", o: ["The pattern of earthquakes around the world", "A continuous series of geological processes that form break down and transform rocks over millions of years", "The way fossils form inside rocks", "The movement of tectonic plates around Earth"], a: 1, exp: "The rock cycle describes how rocks are continuously formed, broken down, and transformed between igneous, sedimentary, and metamorphic types through geological processes over millions of years." },
    { q: "What are the two most abundant elements in Earth's continental crust?", o: ["Iron and nickel", "Aluminium and iron", "Oxygen and silicon", "Carbon and nitrogen"], a: 2, exp: "Oxygen (about 46%) and silicon (about 28%) together make up nearly three-quarters of the mass of Earth's continental crust, mainly as silicate minerals." },
    { q: "What gives Mars its distinctive red colour?", o: ["Clouds of red dust in its atmosphere", "High concentrations of iron oxides on its surface", "Red volcanic rock covering the surface", "Sunlight reflecting off its polar ice caps"], a: 1, exp: "Mars appears red because its surface is rich in iron oxides (similar to rust), giving it a distinctive reddish colour visible from Earth." },
    { q: "What is the difference between magma and lava?", o: ["Magma is hotter than lava", "Magma is molten rock beneath Earth's surface; lava is molten rock that has reached the surface", "Magma is solidified rock; lava is still molten", "There is no difference"], a: 1, exp: "Magma is molten rock found underground; once it erupts through a volcano and reaches the surface, it is called lava." },
    { q: "What is the focus (hypocentre) of an earthquake?", o: ["The point on Earth's surface directly above where an earthquake occurs", "The point inside the Earth where rock slips and the earthquake originates", "The area most severely damaged by an earthquake", "The seismograph station that first detects the earthquake"], a: 1, exp: "The focus or hypocentre is the point inside Earth where the rocks suddenly slip, releasing seismic energy; the point directly above it on the surface is the epicentre." },
    { q: "What is a mould fossil?", o: ["A fossil made entirely of the original bone material", "A hollow negative impression left in rock after an organism's hard parts dissolve", "A solid replica formed when minerals fill a hollow impression", "A footprint preserved in mud"], a: 1, exp: "A mould fossil is a hollow impression (negative shape) left in rock after an organism's hard parts dissolve away; if that hollow later fills with minerals, a cast fossil is formed." },
    { q: "Which of the following is evidence used to support the theory of plate tectonics?", o: ["All continents have the same average temperature", "The matching fit of the coastlines of South America and Africa", "The absence of volcanoes near tectonic plate boundaries", "The uniform age of all oceanic rock"], a: 1, exp: "The jigsaw-like fit of the coastlines of South America and Africa was one of the first observations that suggested the continents were once joined together." },
    { q: "What is relative dating in geology?", o: ["Calculating the exact age of a rock in years using radioactive isotopes", "Determining whether one rock layer is older or younger than another without knowing the exact age in years", "Dating a rock by its colour and texture", "Using fossils to find out exactly how long ago a rock formed"], a: 1, exp: "Relative dating uses the law of superposition and fossil evidence to determine the order of rock layers (older or younger than each other) without giving an exact age in years." },
    { q: "What energy transformation occurs in a hydroelectric dam?", o: ["Chemical energy to electrical energy", "Gravitational potential energy to kinetic energy to electrical energy", "Radiant energy to electrical energy", "Thermal energy to kinetic energy"], a: 1, exp: "In a hydroelectric dam, water stored at height has gravitational potential energy; as it falls this becomes kinetic energy that spins turbines, generating electrical energy." },
    { q: "Which of the following describes an open system?", o: ["A thermos flask that keeps liquid hot", "A sealed container where no matter can escape", "A boiling pot without a lid where steam escapes and heat radiates to the surroundings", "A closed laboratory reaction vessel"], a: 2, exp: "An open system freely exchanges both energy and matter with its surroundings; a boiling uncovered pot loses steam (matter) and heat (energy) to the environment." },
    { q: "What is photosynthesis?", o: ["The process by which cells break down glucose to release energy", "The process by which plants use light energy to convert carbon dioxide and water into glucose and oxygen", "The process by which plants absorb water through their roots", "The process by which animals digest food"], a: 1, exp: "Photosynthesis is the process by which plants (and algae) use light energy to convert carbon dioxide and water into glucose (chemical energy) and oxygen." },
    { q: "What is aerobic cellular respiration?", o: ["The process of breathing air in and out of the lungs", "The process by which living cells break down glucose using oxygen to release energy, producing carbon dioxide and water", "The process by which plants make food from sunlight", "The process of pumping blood around the body"], a: 1, exp: "Aerobic cellular respiration is the process in living cells (in mitochondria) where glucose is broken down using oxygen to release energy, producing carbon dioxide and water as waste." },
    { q: "What type of plate boundary is characterised by two plates sliding past each other horizontally?", o: ["Convergent boundary", "Divergent boundary", "Transform boundary", "Subduction boundary"], a: 2, exp: "A transform boundary is where two tectonic plates slide horizontally past each other; no new crust is created or destroyed but frequent earthquakes occur." },
    { q: "How does the Sun's energy reach Earth?", o: ["Through convection in the atmosphere", "Through conduction along the solar wind", "Through radiation as electromagnetic waves across the vacuum of space", "Through conduction through the Earth's core"], a: 2, exp: "The Sun's energy travels to Earth as radiation (electromagnetic waves including visible light and infrared); radiation is the only energy transfer method that can cross the vacuum of space." },
    { q: "What happens to sediment to form sedimentary rock?", o: ["It is melted and then cooled", "It is subjected to intense heat and pressure without melting", "It is compacted and cemented over time in a process called lithification", "It is carried upward by magma and deposited on the surface"], a: 2, exp: "Sedimentary rock forms when accumulated sediment is compacted by the weight of overlying layers and cemented together by minerals, a process called lithification." },
    { q: "What is an index fossil and why is it useful to geologists?", o: ["A fossil found only in one location used to mark that site", "A fossil of a widespread organism that lived for a short time used to correlate rock layers in different locations", "The largest fossil found in a rock layer", "A fossil that has been dated using radioactive methods"], a: 1, exp: "Index fossils are from species that were widespread but lived for only a short geological time; finding the same index fossil in rock layers at different locations shows those layers formed at the same time." },
    { q: "Which energy form is stored in the food you eat?", o: ["Gravitational potential energy", "Kinetic energy", "Chemical potential energy", "Elastic potential energy"], a: 2, exp: "Food stores chemical potential energy in the bonds between atoms; when cells respire, this chemical energy is released and converted into other forms such as kinetic energy and heat." }
  ],
  "data1": [
    { q: "What is data?", o: ["Only numerical measurements from experiments", "Any collection of facts, measurements, observations, or descriptions that can be recorded and analysed", "Information found only in books and journals", "Only qualitative descriptions of natural events"], a: 1, exp: "Data is any collection of facts, measurements, observations, or descriptions that can be recorded and analysed; it can be numbers, categories, descriptions, or images." },
    { q: "What is the difference between quantitative and qualitative data?", o: ["Quantitative data uses categories; qualitative data uses numbers", "Quantitative data consists of numbers and measurements; qualitative data describes categories or qualities", "Quantitative data is collected in labs; qualitative data is collected outdoors", "There is no difference"], a: 1, exp: "Quantitative data consists of numbers (e.g. temperature, height), while qualitative data describes categories or qualities (e.g. colour, type of rock, species name)." },
    { q: "What is the difference between discrete data and continuous data?", o: ["Discrete data is always more accurate than continuous data", "Discrete data is counted in whole numbers; continuous data is measured on a scale and can take any value", "Discrete data comes from experiments; continuous data comes from surveys", "Continuous data uses categories; discrete data uses measurements"], a: 1, exp: "Discrete data can only take whole number values (e.g. number of students absent), while continuous data can take any value on a scale (e.g. mass, temperature, time)." },
    { q: "A student records the mass of five rocks in grams. What type of data is this?", o: ["Qualitative data", "Discrete quantitative data", "Continuous quantitative data", "Categorical data"], a: 2, exp: "Mass measured on a scale is continuous quantitative data; it can take any numerical value and is measured rather than counted." },
    { q: "What is a digital footprint?", o: ["The size of a file downloaded from the internet", "All the data and traces left behind by a person's online activities", "A type of computer virus", "A security password used for online accounts"], a: 1, exp: "A digital footprint is all the data and traces created by a person's online activities, including posts, searches, location data, and browsing history." },
    { q: "What is the difference between an active and a passive digital footprint?", o: ["An active footprint is created by websites; a passive footprint is created by the user", "An active footprint is created when you deliberately share information; a passive footprint is created without your direct awareness", "Active footprints are deleted automatically; passive footprints are permanent", "There is no difference"], a: 1, exp: "An active digital footprint is created when you deliberately share information (e.g. posting a photo); a passive digital footprint is created without your awareness (e.g. websites tracking your browsing)." },
    { q: "What is a scientific model?", o: ["A small plastic replica of an object used for decoration", "A simplified representation of a real-world phenomenon built from data and observations", "A guess about how something works not based on evidence", "A type of computer program used only by professional scientists"], a: 1, exp: "A scientific model is a simplified representation of a real-world phenomenon built from data and observations; it is used to understand, communicate, and make predictions." },
    { q: "Which of the following is an example of a physical model?", o: ["The word equation for combustion", "A map of Australia showing rainfall", "A scale model of the solar system built from polystyrene balls", "A mathematical formula relating force and mass"], a: 2, exp: "A physical model is a three-dimensional object built to represent something; a scale model of the solar system using polystyrene balls is a physical model." },
    { q: "Which of the following is an example of a conceptual model?", o: ["A plastic replica of the human heart", "A food web diagram showing feeding relationships in an ecosystem", "A mathematical equation for calculating speed", "A computer simulation of weather patterns"], a: 1, exp: "A food web diagram is a conceptual model — it uses diagrams and ideas to represent feeding relationships in an ecosystem, which cannot be directly observed as a whole." },
    { q: "Why are models always simplified versions of reality?", o: ["Because scientists are lazy", "Because models are built from incomplete data and deliberately leave out unnecessary details to make them useful and understandable", "Because real phenomena are too small to study directly", "Because all models are only guesses"], a: 1, exp: "Models simplify reality by including only the most important features; this makes them easier to understand and use, even though they cannot capture every detail of the real phenomenon." },
    { q: "What happens to a scientific model when its predictions do not match new observations?", o: ["The new observations are discarded", "The model is published as final and not changed", "The model is revised, refined, or replaced to better fit the new evidence", "The model is kept but labelled as wrong"], a: 2, exp: "When a model's predictions fail to match new observations, scientists revise or replace the model; this cycle of testing and updating is central to how scientific knowledge advances." },
    { q: "What is data science?", o: ["The study of how to use computers", "An interdisciplinary field that uses statistics, scientific methods, and algorithms to extract knowledge from data", "Only the collection of biological data", "A branch of mathematics dealing with very large numbers"], a: 1, exp: "Data science is an interdisciplinary field combining statistics, computer science, mathematics, and domain expertise to extract knowledge and insights from data." },
    { q: "What is an algorithm in data science?", o: ["A type of graph used to display data", "A step-by-step computational procedure for processing data to detect patterns", "A measure of the centre of a dataset", "A type of scientific experiment"], a: 1, exp: "An algorithm is a step-by-step set of rules or instructions that a computer follows to process data; algorithms allow computers to detect patterns in very large datasets." },
    { q: "What is the mean of the dataset: 4, 7, 9, 6, 4?", o: ["5", "6", "7", "4"], a: 1, exp: "The mean is calculated by adding all values (4+7+9+6+4 = 30) and dividing by the number of values (5), giving 30 / 5 = 6." },
    { q: "What is the range of the dataset: 12, 18, 15, 20, 10?", o: ["8", "10", "15", "6"], a: 1, exp: "The range is the largest value minus the smallest value: 20 minus 10 = 10." },
    { q: "What does the range of a dataset tell you?", o: ["The most common value in the dataset", "The middle value when the data is arranged in order", "How spread out the data is; the difference between the largest and smallest values", "The calculated average of all the values"], a: 2, exp: "The range measures how spread out or variable a dataset is; a small range indicates consistent measurements while a large range indicates high variability." },
    { q: "What is the mode of the dataset: 3, 5, 5, 7, 8, 5, 3?", o: ["3", "5", "7", "8"], a: 1, exp: "The mode is the value that appears most frequently in a dataset; 5 appears three times, more than any other value, so the mode is 5." },
    { q: "What is the median of the dataset: 2, 5, 7, 9, 11?", o: ["2", "5", "7", "9"], a: 2, exp: "The median is the middle value when data is arranged in order; in the dataset 2, 5, 7, 9, 11, the middle (third) value is 7." },
    { q: "What is the difference between accuracy and reliability in scientific investigations?", o: ["Accuracy means getting consistent results; reliability means getting the correct result", "Accuracy refers to how close measurements are to the true value; reliability refers to how consistently a measurement can be reproduced", "Accuracy and reliability mean the same thing", "Accuracy refers to the number of trials; reliability refers to the instruments used"], a: 1, exp: "Accuracy is how close a measurement is to the true value; reliability is how consistently the same result is obtained when a measurement is repeated." },
    { q: "A thermometer reads 2 degrees Celsius higher than the true value every single time it is used. How would you describe this data?", o: ["Accurate and reliable", "Accurate but not reliable", "Reliable but not accurate", "Neither accurate nor reliable"], a: 2, exp: "The thermometer gives consistent (reliable) readings, but they are always 2 degrees above the true value, so the data is reliable but not accurate." },
    { q: "Why should scientists conduct multiple trials in an investigation?", o: ["To make the experiment take longer", "To use up more equipment", "To reduce the effect of random errors and increase the reliability of results", "To make the results look more impressive"], a: 2, exp: "Repeating trials reduces the impact of random errors and allows calculation of a mean, making the results more reliable and representative of the true value." },
    { q: "What is the independent variable in a scientific investigation?", o: ["What is measured as a result of the change", "What is deliberately changed by the investigator", "What is kept constant to make the test fair", "The conclusion drawn from the results"], a: 1, exp: "The independent variable is the factor that the investigator deliberately changes to see how it affects the dependent variable." },
    { q: "What is the dependent variable in a scientific investigation?", o: ["What is deliberately changed by the investigator", "What is measured as a result of the change to the independent variable", "What is kept constant to make the test fair", "The hypothesis of the investigation"], a: 1, exp: "The dependent variable is the quantity that is measured during an investigation; it depends on the changes made to the independent variable." },
    { q: "Why is it important to control variables in a scientific investigation?", o: ["To speed up the experiment", "To make the experiment more interesting", "To ensure that only the independent variable changes making the test fair and results valid", "To reduce the number of measurements needed"], a: 2, exp: "Controlling variables (keeping all other factors constant) ensures that any change in the dependent variable is caused only by the independent variable, making the test fair." },
    { q: "What makes a question scientific?", o: ["Any question about nature is scientific", "A question is scientific if it is specific, testable, and can be answered by collecting and analysing data", "A question is scientific only if it involves mathematics", "A question is scientific if a scientist asks it"], a: 1, exp: "A scientific question is one that is specific and testable; it identifies variables that can be measured and can be answered through data collection and analysis." },
    { q: "What is a hypothesis?", o: ["A conclusion drawn after an experiment", "A testable prediction about the expected outcome of an investigation based on prior knowledge", "A list of materials needed for an experiment", "A summary of all previous research on a topic"], a: 1, exp: "A hypothesis is a testable prediction, usually written as: if the independent variable changes then the dependent variable will change, because of a stated reason." },
    { q: "What is peer review in science?", o: ["When students mark each other's homework", "The process by which other qualified scientists critically evaluate a scientist's methods and findings before they are published", "The process of repeating an experiment in the same laboratory", "When a scientist reads their own work to check for errors"], a: 1, exp: "Peer review is the process by which other qualified scientists examine and critique a researcher's methods, data, and conclusions before the work is published in a scientific journal." },
    { q: "What is the difference between interpolation and extrapolation when reading a graph?", o: ["Interpolation predicts beyond the data range; extrapolation estimates within the data range", "Interpolation estimates a value within the range of existing data; extrapolation predicts values beyond the data range", "They are the same process", "Interpolation applies to tables; extrapolation applies to graphs"], a: 1, exp: "Interpolation estimates a value within the range of measured data (lower uncertainty); extrapolation predicts a value beyond the range of the data (higher uncertainty)." },
    { q: "Why does extrapolation carry more uncertainty than interpolation?", o: ["Because extrapolated values cannot be written on a graph", "Because extrapolation predicts beyond the data range where the trend may not continue in the same way", "Because interpolation uses more data points than extrapolation", "Because extrapolation always gives a negative value"], a: 1, exp: "Extrapolation extends predictions beyond the measured data range; conditions may change outside that range meaning the observed trend might not continue." },
    { q: "What is an outlier in a dataset?", o: ["The most common value in the dataset", "A data point that does not fit the general pattern and is far from the other values", "The average of all values in the dataset", "The largest value in the dataset"], a: 1, exp: "An outlier is a data point that is very different from the other values and does not fit the general trend; it should be investigated to determine whether it is a real result or an error." },
    { q: "What is a computer simulation?", o: ["A physical model built in a laboratory", "A virtual experiment in which a computer model is used to test the effect of changing variables", "A type of graph produced by a spreadsheet", "A method of collecting data using sensors"], a: 1, exp: "A computer simulation runs a virtual experiment using a mathematical model; variables can be changed quickly and the model re-run many times to investigate a wide range of scenarios." },
    { q: "What are the steps of the data science process in the correct order?", o: ["Collect data, formulate a question, analyse, communicate", "Formulate a question, collect data, organise and clean data, analyse, communicate results", "Communicate results, collect data, analyse, formulate a question", "Analyse data, formulate a question, collect, communicate"], a: 1, exp: "The data science process begins with a question, then data are collected, organised and cleaned, analysed for patterns, and finally the results are communicated." },
    { q: "What is the difference between a scientific theory and a guess?", o: ["There is no difference", "A scientific theory is a well-substantiated explanation supported by large amounts of evidence from multiple independent sources and extensive testing", "A theory is an early stage of an idea before any evidence is collected", "A theory is a fact that can never be changed"], a: 1, exp: "In science, a theory is a well-tested well-supported explanation (like the theory of plate tectonics or germ theory); it is the strongest explanation science can offer, not a mere guess." },
    { q: "What is the mean of a dataset?", o: ["The most frequently occurring value", "The middle value when data is arranged in order", "The sum of all values divided by the number of values", "The difference between the largest and smallest values"], a: 2, exp: "The mean (arithmetic average) is calculated by adding all the values in a dataset and dividing the total by the number of values." },
    { q: "When is the median a better measure of centre than the mean?", o: ["When all values in the dataset are equal", "When the dataset has an even number of values", "When a dataset contains extreme outliers that would pull the mean far from most data points", "When the data is quantitative"], a: 2, exp: "The median is resistant to extreme values (outliers) because it only depends on the order of values, not their size; the mean can be heavily influenced by one very large or very small value." },
    { q: "A scientist wants to check if a model's predictions are correct. What should they do?", o: ["Repeat the model on the same data", "Collect new independent data and compare the model's predictions to those observations", "Change the model until it fits the original data", "Ask other scientists if they think the model looks correct"], a: 1, exp: "To test a model, scientists collect new independent data and compare the model's predictions to the new observations; this is the core of the scientific method." },
    { q: "What type of model uses equations and numerical relationships to represent how variables interact?", o: ["Physical model", "Conceptual model", "Mathematical model", "Graphical model"], a: 2, exp: "A mathematical model uses equations and numerical rules to describe how variables interact; Newton's second law (F = ma) is a classic example of a mathematical model." },
    { q: "Why is it important to have multiple independent lines of evidence when building a scientific model?", o: ["It makes the model more complicated and therefore more impressive", "Multiple independent datasets that all point to the same conclusion increase confidence that the model is correct", "Scientists are required by law to use many data sources", "More data always makes a model more complex and harder to use"], a: 1, exp: "When multiple independent types of data all support the same model, it is much less likely that all of them are wrong or coincidental, so confidence in the model increases." },
    { q: "What does it mean for a scientific investigation to be repeatable?", o: ["The same scientist can do the experiment many times in the same place", "Different scientists doing the same experiment in different places get consistent results", "The experiment gives exactly the same results every single time", "The experiment uses the same equipment each time"], a: 1, exp: "A repeatable (reproducible) investigation is one where different scientists using the same method in different settings obtain consistent results, which increases confidence in the findings." },
    { q: "A student's five ruler-drop trials gave results of 14, 15, 15, 16, 15 cm but the true value is 12 cm. How would you describe this data?", o: ["Accurate and reliable", "Accurate but not reliable", "Reliable but not accurate", "Neither accurate nor reliable"], a: 2, exp: "The trials are very close together (reliable/consistent), but they are all higher than the true value of 12 cm, so the data is reliable but not accurate." },
    { q: "What is primary data?", o: ["Data collected from textbooks", "Data found on the internet", "Data that you collect yourself through direct observation or measurement", "Data from government reports"], a: 2, exp: "Primary data is data you collect directly yourself through observation, experiment, or measurement, as opposed to secondary data which is collected by someone else." },
    { q: "What is secondary data?", o: ["Data you collect through your own experiments", "Data already collected by someone else such as published research, government statistics, or databases", "Data that is incorrect or unreliable", "Data collected from only one source"], a: 1, exp: "Secondary data is data that has already been collected by someone else and is available in published sources such as journals, government websites, or databases." },
    { q: "A student plants seeds and measures their height every day for two weeks. Which type of variable is the height of the plants?", o: ["Independent variable", "Controlled variable", "Dependent variable", "Categorical variable"], a: 2, exp: "The height of the plants is the dependent variable; it is measured as a result of whatever conditions such as light, water, or soil the student is investigating." },
    { q: "Which of the following is a scientific question that can be investigated with data?", o: ["Is science the most interesting subject?", "Does increasing the amount of fertiliser added to soil increase the height of bean plants after 4 weeks?", "Should all students study science?", "What is the best sport to play?"], a: 1, exp: "This is a scientific question because it specifies the independent variable (amount of fertiliser), the dependent variable (plant height), and a clear context that can be tested by collecting data." },
    { q: "What is the purpose of a line of best fit on a scatter plot?", o: ["To connect every data point together", "To show the exact value of every measurement", "To represent the general trend in the data allowing predictions to be made", "To remove outliers from the data"], a: 2, exp: "A line of best fit is drawn through the data points on a scatter plot to show the overall trend; it allows values to be estimated from the graph." },
    { q: "If two groups measure the same quantity and Group A has a range of 2 while Group B has a range of 15, what does this suggest?", o: ["Group A collected more data than Group B", "Group A's measurements are more consistent and reliable than Group B's", "Group B's measurements are more accurate than Group A's", "Group A made more errors than Group B"], a: 1, exp: "A smaller range means the measurements are clustered closely together, indicating greater consistency (reliability); Group A's small range suggests their measurements were more repeatable." },
    { q: "What is an investigable scientific question?", o: ["Any question that a scientist finds interesting", "A question that is vague and open-ended", "A specific question that identifies variables that can be measured and tested through data collection", "A question that only experts can answer"], a: 2, exp: "An investigable scientific question is specific, identifies measurable variables, and can be answered through data collection and analysis." },
    { q: "Calculate the mean of this dataset: 5, 8, 6, 5, 10, 6, 5.", o: ["5", "6", "7", "8"], a: 2, exp: "Add all values: 5+8+6+5+10+6+5 = 45, then divide by 7 values: 45 / 7 = approximately 6.4, which rounds to 6 as the nearest whole number." },
    { q: "A dataset has the values 10, 12, 11, 10, 13. What is the mode?", o: ["10", "11", "12", "13"], a: 0, exp: "The mode is the most frequently occurring value; 10 appears twice in this dataset while all other values appear once, so the mode is 10." },
    { q: "What does it mean to say data science is interdisciplinary?", o: ["It only uses biology and chemistry", "It draws knowledge and tools from many fields including statistics, computer science, mathematics, and subject expertise", "It is studied only at university level", "It deals exclusively with very large datasets"], a: 1, exp: "Interdisciplinary means drawing on multiple fields; data science combines statistics, computer science, mathematics, and knowledge of the subject being studied." },
    { q: "Why is it important to clearly label graphs and tables when recording data?", o: ["It makes the report look longer", "So that other scientists can understand, interpret, and reproduce the investigation", "Because all scientific graphs must have exactly three labels", "So that the graph takes up more space in the report"], a: 1, exp: "Clear labels (including axis labels, units, and titles) allow other scientists to understand what was measured, how, and what the results show, which is essential for reproducibility and peer review." },
    { q: "Which of the following best describes a positive trend in a graph?", o: ["As the independent variable increases the dependent variable decreases", "As the independent variable increases the dependent variable also increases", "The data shows no relationship between the two variables", "The graph shows a horizontal line at the same value"], a: 1, exp: "A positive trend means that as the independent variable increases, the dependent variable also increases; for example, as temperature increases, dissolving time generally decreases." },
    { q: "What is a controlled variable in a scientific investigation?", o: ["The variable that is deliberately changed", "The variable that is measured", "A variable that is kept constant to ensure a fair test", "The variable that produces the results"], a: 2, exp: "A controlled variable is one that is kept constant throughout the investigation so that only the independent variable can cause changes in the dependent variable, making the test fair." },
    { q: "What does it mean to say a model generates predictions?", o: ["The model was built before any data was collected", "The model can be used to estimate what will happen under conditions not yet tested", "The model is always 100% correct", "The model was created by a computer"], a: 1, exp: "A good scientific model can generate predictions: it can estimate outcomes in situations that have not yet been directly observed, and those predictions can then be tested to evaluate the model." },
    { q: "Why is it useful to calculate the mean from repeated trials rather than just recording one result?", o: ["The mean is always more accurate than any single trial", "Averaging multiple trials reduces the effect of random errors and gives a more reliable estimate of the true value", "The mean makes the data easier to graph", "Calculating the mean is required by law in all science investigations"], a: 1, exp: "Averaging repeated trials reduces the influence of random errors on the result, giving a more reliable and representative estimate of the true value than a single measurement alone." }
  ]
};
